
export default {
	provide() {
		return {
			reload: this.reload
		};
	},
	data() {
		return {
			isRouterAlive: true,
			dateUrl: null,
			Login_token: '',
			Message: '',
			datetime: '',
			Login_datetime: '',
			appmc: false
		};
	},
	onLaunch: function() {
		// console.log('App Launch');
	},
	onHide: function() {
		// console.log('App Hide');
	},
	onShow() {
		var isRouterAlive= true;
		// var url= encodeURIComponent('http://voa.yangguangzhiye.cn/custom/pages/subscribe/subscribe?cuid=81277');
		var ref_url = "http://127.0.0.1:81/custom";
		// var ref_url = "http://voa.yangguangzhiye.cn/custom";
		var dateUrl= null;
		var http_url= 'http://woa.yangguangzhiye.cn/getLogin_qy.html';
		var Code= '';
		var Login_token='';
		var Message= '';
		var datetime= '';
		var Login_datetime='';
		var appmc= false;
		var systemid = 108;
		var api_token =  '602a0de21ef5949221ae1d90021ce2584e2ecef1';
		
		// 获取回调域名h5模式 history
		//如果回调域名中传来的code=202，提示消息
		if (this.$route.query.Code == 202) {
			Message = this.$route.query.Message;
			appmc = true;
		}
		//判断是否存储Login_token 如果有存储超时10800要重新请求
		var loginToken = ''
		uni.getStorage({
		    key: 'Login_token',
		    success: function (res) {
				loginToken = res.data;
		    }
		});
		
		if (!loginToken) {
			//hash模式下(带#的url),获取方式
			const geturlkey= function(name){
			    return decodeURIComponent((new RegExp('[?|&]' + name + '=' + '([^&;]+?)(&|#|;|$)').exec(location.href) || [, ""])[1].replace(/\+/g, '%20')) || null
			}
			let Code = geturlkey('Code');
			if (Code) {
				//code=200 Login_token保存至浏览器端
				if (Code == 200) {
					datetime = Date.parse(new Date());
					let loginToken = geturlkey('Login_token');
					uni.setStorage({
					    key: 'Login_token',
					    data: loginToken,
					    success: function () {
					    }
					});
					let url = location.href;
					let hash = '';
					let cuid = geturlkey('cuid');
					if (url.indexOf('?') != -1) {
						hash = url.split('?')[0];
						if(cuid){
							uni.setStorage({
							    key:'cuid',
							    data: cuid,
							    success () {
							    }
							});
							uni.reLaunch({
								url:'/pages/subscribe/subscribe'
							})
						}else{
							uni.reLaunch({
								url:'/pages/home/home'
							})
						}
					}
				}else{
					uni.showToast({
						icon:'none',
						title:this.$route.query.Message
					})
				}
			} else {
				dateUrl = new Date();
				dateUrl = Date.parse(dateUrl) / 1000;
				let urls = this.$route.path;
				let datas = this.$route.query;
				var urlss = ref_url+ urls;
				let uri = location.href;
				let urlsss = encodeURIComponent(uri);
				location.href = http_url+'?systemid='+systemid+'&api_token='+api_token+'&timestamp='+dateUrl+'&redirect_uri='+urlsss;
			}
		}else{
		   const geturlkey= function(name){
		       return decodeURIComponent((new RegExp('[?|&]' + name + '=' + '([^&;]+?)(&|#|;|$)').exec(location.href) || [, ""])[1].replace(/\+/g, '%20')) || null
		   }
		   let cuid = geturlkey('cuid');
		   if(cuid){
			   uni.setStorage({
			       key:'cuid',
			       data: cuid,
			       success () {
			       }
			   });
			   uni.reLaunch({
			   	url:'/pages/subscribe/subscribe'
			   })
		   }
		   
		}
	},
	methods: {
		reload() {
			this.isRouterAlive = false;
			this.$nextTick(function() {
				this.isRouterAlive = true;
			});
		},
		appMc_hide() {
			this.appmc = false;
		}
	}
};
